import './App.css';
import Hero from './components/Hero';
import Gallery from './components/Gallery';
import { menu } from './menu';

function App(): JSX.Element {
  const menuRef = useRef(null)

  return (
    <div className="app">
      <Hero />
      {menu.map((section) => (
        <Gallery
          ref = {section.title == "Ramen"}
          key={section.title}
          title={section.title}
          items={section.items}
        />
      ))}
    </div>
  );
}

export default App;
